public class ModEffects {
    public static final StatusEffect CUSTOM_EFFECT = new StatusEffect(StatusEffectCategory.BENEFICIAL, 0x00FF00);
    public static void register() {
        Registry.register(Registries.STATUS_EFFECT, new Identifier("modid", "custom_effect"), CUSTOM_EFFECT);
    }
}

@Override
public boolean canApplyUpdateEffect(int duration, int amplifier) {
    return true;
}
@Override
public void applyUpdateEffect(LivingEntity entity, int amplifier) {
    entity.heal(2.0f);
}

public class ModPotions {
    public static final Potion CUSTOM_POTION = new Potion(new StatusEffectInstance(ModEffects.CUSTOM_EFFECT, 3600, 0));
    public static void register() {
        Registry.register(Registries.POTION, new Identifier("modid", "custom_potion"), CUSTOM_POTION);
    }
}
